// Обработка входящих deeplink-ов (дуэльные приглашения)
useEffect(() => {
  const handleUrl = (url: string) => {
    // https://badloar-star.github.io/phraseman/duel/ROOMID
    // или phraseman://duel/ROOMID
    const match = url.match(/\/duel\/([A-Z0-9]+)/i);
    if (match) {
      const roomId = match[1];
      router.push({ pathname: '/duel_join' as any, params: { roomId } });
    }
  };
  Linking.getInitialURL().then(url => { if (url) handleUrl(url); });
  const sub = Linking.addEventListener('url', ({ url }) => handleUrl(url));
  return () => sub.remove();
}, []);
